import Foundation

// Generated from Hue scene artwork metadata. Do not edit by hand.
enum SceneArtworkCatalog {
    static let imageExtension = "webp"

    static var allImageNames: [String] {
        bundledImageNames.sorted()
    }

    static func imageName(forPublicImage image: ResourceLink?) -> String? {
        guard let image, image.rtype == "public_image" else { return nil }
        return publicImageNames[image.rid]
    }

    static func imageName(forSceneName name: String) -> String? {
        let normalized = normalizedSceneName(name)
        if bundledImageNames.contains(normalized) {
            return normalized
        }
        return bundledImageNameAliases[normalized]
    }

    static func url(forImageNamed name: String) -> URL? {
        for bundle in [Bundle.main, Bundle.module] {
            if let url = bundle.url(
                forResource: name,
                withExtension: imageExtension,
                subdirectory: "SceneImages"
            ) {
                return url
            }
        }
        return nil
    }

    private static func normalizedSceneName(_ name: String) -> String {
        name
            .lowercased()
            .replacingOccurrences(of: "'", with: "")
            .replacingOccurrences(of: "’", with: "")
            .split { character in
                !character.isLetter && !character.isNumber
            }
            .joined(separator: "_")
    }

